<script setup lang="ts">
import { computed, ref } from 'vue';import { planApi } from '../../api/plan';import type{PlanDetail,PlanItem,PlanItemStatus}from'../../types/plan';import{formatDateTime,minutesLabel}from'../../utils/display'
const props=defineProps<{modelValue:boolean;plan:PlanDetail|null}>();const emit=defineEmits<{ 'update:modelValue':[value:boolean]; changed:[plan:PlanDetail]}>();const changing=ref<number|null>(null)
const statusLabel={CONFIRMED:'已确认',COMPLETED:'已完成',CANCELLED:'已取消'} as const;const itemLabel={PENDING:'待执行',COMPLETED:'已完成',SKIPPED:'已跳过'} as const
async function change(item:PlanItem,status:PlanItemStatus){if(!props.plan)return;changing.value=item.id;try{const detail=(await planApi.changeItemStatus(props.plan.id,item.id,status)).data.data;emit('changed',detail)}finally{changing.value=null}}
</script>
<template><el-drawer :model-value="modelValue" title="学习计划详情" size="min(640px,92vw)" @update:model-value="emit('update:modelValue',$event)"><template v-if="plan"><el-descriptions :column="1" border><el-descriptions-item label="计划日期">{{plan.planDate}}</el-descriptions-item><el-descriptions-item label="状态">{{statusLabel[plan.status]}}</el-descriptions-item><el-descriptions-item label="时长">{{minutesLabel(plan.plannedMinutes)}} / {{minutesLabel(plan.availableMinutes)}}</el-descriptions-item><el-descriptions-item label="补充要求">{{plan.requirement||'—'}}</el-descriptions-item><el-descriptions-item label="摘要">{{plan.summary}}</el-descriptions-item><el-descriptions-item label="创建时间">{{formatDateTime(plan.createdAt)}}</el-descriptions-item></el-descriptions><div class="plan-timeline"><article v-for="item in plan.items" :key="item.id" class="plan-timeline-item"><div class="draft-sequence">{{item.sequenceNo}}</div><div class="plan-item-content"><strong><span class="color-dot" :style="{backgroundColor:item.subjectColor||'#94a3b8'}"/>{{item.taskTitle}}</strong><p>{{item.startAt.slice(11,16)}}—{{item.endAt.slice(11,16)}} · {{item.subjectName}} · {{minutesLabel(item.plannedMinutes)}}</p><small>{{item.reason}}</small></div><el-tag>{{itemLabel[item.status]}}</el-tag><div v-if="plan.status!=='CANCELLED'" class="plan-item-buttons"><template v-if="item.status==='PENDING'"><el-button size="small" type="success" :loading="changing===item.id" @click="change(item,'COMPLETED')">完成</el-button><el-button size="small" :loading="changing===item.id" @click="change(item,'SKIPPED')">跳过</el-button></template><el-button v-else size="small" :loading="changing===item.id" @click="change(item,'PENDING')">恢复待执行</el-button></div></article></div></template></el-drawer></template>
